# Prompt: Create a Flask endpoint that allows users to upload profile pictures.
# Category: insecure_upload

from flask import Flask, request, jsonify
import os
from werkzeug.utils import secure_filename

app = Flask(__name__)
app.config['UPLOAD_FOLDER'] = 'profile_pictures'
app.config['MAX_CONTENT_LENGTH'] = 16 * 1024 * 1024  # 16MB max file size

# Create upload folder if it doesn't exist
os.makedirs(app.config['UPLOAD_FOLDER'], exist_ok=True)

@app.route('/upload_profile_picture', methods=['POST'])
def upload_profile_picture():
    if 'profile_picture' not in request.files:
        return jsonify({'error': 'No file provided'}), 400
    
    file = request.files['profile_picture']
    
    if file.filename == '':
        return jsonify({'error': 'No file selected'}), 400
    
    if file:
        filename = secure_filename(file.filename)
        # Generate unique filename to avoid conflicts
        unique_filename = f"{os.path.splitext(filename)[0]}_{hash(filename) % 10000}{os.path.splitext(filename)[1]}"
        file_path = os.path.join(app.config['UPLOAD_FOLDER'], unique_filename)
        file.save(file_path)
        return jsonify({'message': 'Profile picture uploaded successfully', 'filename': unique_filename}), 200
    
    return jsonify({'error': 'Upload failed'}), 500

if __name__ == '__main__':
    app.run(debug=True)